// Reads query params from the webhook.
// Required: customer_id
// Optional: supplier_id, limit
//
// Example:
//   GET /webhook/ops-push?customer_id=<uuid>&supplier_id=<uuid>&limit=25
//
// Notes:
// - This workflow pushes to ONE OPS credential (selected in the OPS nodes).
// - Ensure that credential matches the provided customer_id.

const first = $input.first().json ?? {};
const q = first.query ?? first.queryParameters ?? {};

const customer_id = q.customer_id ?? q.customerId;
if (!customer_id) {
  throw new Error('Missing required query param: customer_id');
}

const supplier_id = q.supplier_id ?? q.supplierId ?? null;
const limitRaw = q.limit ?? 25;
const limit = Math.max(1, Math.min(200, Number(limitRaw) || 25));

const api_base = $env.API_HUB_BASE_URL || 'http://host.docker.internal:8000';

const url = new URL(`${api_base.replace(/\/$/, '')}/api/products`);
url.searchParams.set('limit', String(limit));
if (supplier_id) url.searchParams.set('supplier_id', String(supplier_id));

return [{
  json: {
    api_base,
    customer_id: String(customer_id),
    supplier_id: supplier_id ? String(supplier_id) : null,
    limit,
    products_url: url.toString(),
  },
}];

// Normalize the /api/products response into one item per product.
// Carries customer_id and api_base forward for downstream nodes.

const ctx = $node['Parse Params'].json;
const items = $input.all();

const list = items.flatMap((i) => {
  const j = i.json;
  if (Array.isArray(j)) return j;
  if (j && Array.isArray(j.data)) return j.data;
  if (j && Array.isArray(j.body)) return j.body;
  return j && typeof j === 'object' ? [j] : [];
});

return list
  .filter((p) => p && (p.id || p.product_id))
  .map((p) => ({
    json: {
      api_base: ctx.api_base,
      customer_id: ctx.customer_id,
      product_id: String(p.id ?? p.product_id),
      product_name: p.product_name ?? p.name ?? p.products_title ?? 'Unnamed',
      supplier_name: p.supplier_name ?? null,
    },
  }));

// Builds JSON-string inputs for OPS setProduct + setProductPrice.
//
// IMPORTANT:
// - The OnPrintShop node expects setProduct_input/setProductPrice_input as JSON strings.
// - This workflow uses size_id=0 and category_id=0 as defaults; adjust if your OPS instance requires these.

const items = $input.all();

function minNumber(values) {
  const nums = values.filter((v) => typeof v === 'number' && Number.isFinite(v));
  if (!nums.length) return null;
  return Math.min(...nums);
}

return items.map((item) => {
  // Merge node returns combined json from both inputs.
  const merged = item.json ?? {};
  const payload = merged.product ? merged : (merged.payload ?? merged);

  const productMeta = payload.product ?? {};
  const variants = Array.isArray(payload.variants) ? payload.variants : [];

  const minFinal = minNumber(variants.map((v) => v.final_price));
  const minBase = minNumber(variants.map((v) => v.base_price));

  const setProductInput = {
    category_id: 0,
    visible: 1,
    products_title: productMeta.name ?? merged.product_name ?? 'Unnamed',
    products_internal_title: productMeta.supplier_sku ?? merged.product_id,
  };

  const setProductPriceTemplate = {
    product_price_id: 0,
    products_id: 0,
    qty: 1,
    qty_to: 999999,
    price: minFinal ?? 0,
    vendor_price: minBase ?? 0,
    size_id: 0,
    visible: '1',
  };

  return {
    json: {
      api_base: merged.api_base,
      customer_id: merged.customer_id,
      product_id: merged.product_id,
      product_name: merged.product_name,
      payload,
      setProduct_input: JSON.stringify(setProductInput, null, 2),
      setProductPrice_template: setProductPriceTemplate,
    },
  };
});

// Combines the setProduct result with the pre-built price template.
// setProduct returns: { result, message, products_id }

const setProduct = $input.first().json ?? {};
const ctx = $node['Build OPS Inputs'].json;

const products_id = setProduct.products_id ?? setProduct.productsId;
if (!products_id) {
  throw new Error(`setProduct did not return products_id. Got: ${JSON.stringify(setProduct)}`);
}

const price = { ...(ctx.setProductPrice_template ?? {}) };
price.products_id = Number(products_id);

return [{
  json: {
    api_base: ctx.api_base,
    customer_id: ctx.customer_id,
    product_id: ctx.product_id,
    ops_product_id: String(products_id),
    setProductPrice_input: JSON.stringify(price, null, 2)
  }
}];
